# Explorer: complete from packet starter + instruction contract
def assess(record: dict) -> str:
    required = {'digest_stable', 'case_id', 'source_change_rebuilds', 'dependency_layer_reused', 'lock_copied_before_source'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('lock_copied_before_source') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT'

valid = {"case_id": 'CASO-SYN-1A', 'lock_copied_before_source': True, 'dependency_layer_reused': True, 'source_change_rebuilds': True, 'digest_stable': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'lock_copied_before_source': False, 'dependency_layer_reused': False, 'source_change_rebuilds': False, 'digest_stable': False}
missing = {k: valid[k] for k in valid if k != 'digest_stable'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

